#include <stdio.h>

// This function REQUIRES an integer to be passed to it
void printScore(int score) {
    printf("Your score is: %d\n", score);
}

int main() {
    printScore(50);  // We pass '50' as the Argument
    printScore(100); // We pass '100' as the Argument
    return 0;
}

#include <stdio.h>

void calculateArea(int width, int height) {
    int area = width * height;
    printf("Area: %d\n", area);
}

int main() {
    calculateArea(5, 10);
    return 0;
}
